1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge cases: simplest ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const out = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(out.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // --- Base premiums for main items (single item, newcomer baseline) ---
15	  // Note: a lone item for a 0-year customer gets first-insurance +10% and fee.
16	  // Use these to pin base premiums via the integration math where needed.
17	  it.todo("single sword, 0 years → base 100 G + 10% first + 5 fee = 115 G");
18	  it.todo("single amulet, 0 years → base 60 G + 10% first + 5 fee = 71 G");
19	  it.todo("single staff, 0 years → base 80 G + 10% first + 5 fee = 93 G");
20	  it.todo("single potion, 0 years → base 40 G + 10% first + 5 fee = 49 G");
21	
22	  // --- Components: per-component premium and building block ---
23	  it.todo("2 runes → base premium 50 G (25 each, no block)");
24	  it.todo("3 runes → base premium 60 G (block of 3 applies)");
25	  it.todo("4 runes → base premium 100 G (no block — block requires exactly 3)");
26	  it.todo("7 runes → base premium 175 G (one block of 3 = 60, plus 4×25 = 100)");
27	
28	  // --- 'Alike' components ---
29	  it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types)");
30	  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");
31	
32	  // --- Premium modifiers in isolation ---
33	  it.todo("cursed sword adds 50% of its base premium (curse surcharge)");
34	  it.todo("sword enchantment 5 → high-enchantment +30% surcharge applies");
35	  it.todo("sword enchantment 4 → no high-enchantment surcharge");
36	  it.todo("sword enchantment 5 and cursed → both surcharges apply");
37	  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
38	  it.todo("follow-up contract → 15% discount on each contract after the first");
39	
40	  // --- Modifier scope on multi-item policies ---
41	  it.todo("cursed sword (100) + plain amulet (60) → policy base 160; curse adds 50 (50% of sword) → 210 before further modifiers and fee");
42	
43	  // --- Rounding ---
44	  it.todo("premium yielding 197.5 G → final premium 198 G (rounded up)");
45	  it.todo("payout yielding 350.5 G → final payout 350 G (rounded down)");
46	
47	  // --- Integration examples ---
48	  it.todo("newcomer cursed sword (steel, ench 3): 100 base + 50 curse + 10 first = 160 + 5 fee = 165 G");
49	  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7) → 160 G (100 +50 +30 -20 +10 -15 = 155 +5 fee)");
50	
51	  // --- Claim: standard reimbursement ---
52	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
53	  it.todo("damage to a rune (value 250), damage 200 → payout 100 (full minus 100 deductible)");
54	
55	  // --- Claim: enchantment threshold and dragon material ---
56	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible: 500-100)");
57	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (full, then deductible: 800-100)");
58	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% wins, then deductible: 500-100)");
59	  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-ench clause applies, then deductible)");
60	
61	  // --- Claim: deductible per damage event ---
62	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per damaged item)");
63	
64	  // --- Claim: cap ---
65	  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
66	  it.todo("cursed sword → cap 2000 (based on unmodified insurance value, premium modifiers do not raise cap)");
67	  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block discount affects premium only)");
68	  it.todo("sword (cap 2000), two successive 1500 claims: first → payout 1400, remainingCap 600; second → payout 600, remainingCap 0");
69	
70	  // --- Multiple items of same type ---
71	  it.todo("policy covers two swords → insurance sum 2000, cap 4000; dragon attack damages both → each its own deductible");
72	
73	  // --- Error cases ---
74	  it.todo("quote with unknown item type (broomstick) → throws / non-zero exit");
75	  it.todo("claim references item not in policy (amulet when only sword insured) → throws / non-zero exit");
76	  it.todo("claim with more damage entries of a type than insured (two swords, one insured) → throws / non-zero exit");
77	  it.todo("claim with negative damage amount (-200) → throws / non-zero exit");
78	});
